/**
 * Tests for sequant_run MCP tool async refactor
 * Issue #388: Replace spawnSync with async spawn
 *
 * Covers:
 * - AC-1: spawn instead of spawnSync
 * - AC-4: Output buffered, truncated to 2000 chars
 * - AC-5: Timeout preserved (30 min default)
 * - AC-6: Tests updated for async
 * - Derived AC-7: Handle ENOENT with descriptive error
 * - Derived AC-8: No orphan processes on timeout/cancel
 */

import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";
import type { ChildProcess } from "child_process";

// Check if MCP SDK is available
const mcpSdkAvailable = await import("@modelcontextprotocol/sdk/server/mcp.js")
  .then(() => true)
  .catch(() => false);

describe.skipIf(!mcpSdkAvailable)("sequant_run tool async refactor", () => {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  let client: any;
  let cleanup: () => Promise<void>;
  let mockSpawn: ReturnType<typeof vi.fn>;

  beforeEach(async () => {
    // Mock child_process.spawn before importing the tool
    const childProcessModule = await import("child_process");
    mockSpawn = vi.fn();
    vi.doMock("child_process", () => ({
      spawn: mockSpawn,
      spawnSync: childProcessModule.spawnSync, // Keep spawnSync for other uses
    }));

    const { createServer } = await import("../src/mcp/server.js");
    const { Client } =
      await import("@modelcontextprotocol/sdk/client/index.js");
    const { InMemoryTransport } =
      await import("@modelcontextprotocol/sdk/inMemory.js");

    const server = createServer("1.0.0-test");
    const clientInstance = new Client({
      name: "test-client",
      version: "1.0.0",
    });

    const [clientTransport, serverTransport] =
      InMemoryTransport.createLinkedPair();
    await Promise.all([
      clientInstance.connect(clientTransport),
      server.connect(serverTransport),
    ]);

    client = clientInstance;
    cleanup = async () => {
      await clientInstance.close();
      await server.close();
    };
  });

  afterEach(async () => {
    await cleanup();
    vi.doUnmock("child_process");
    vi.clearAllMocks();
  });

  describe("AC-1: spawn instead of spawnSync", () => {
    describe("positive path", () => {
      it("should use child_process.spawn (not spawnSync) and return Promise that resolves after process exit", async () => {
        // Given: A valid issue number array
        const issues = [123];

        // Mock spawn to return a mock ChildProcess
        const mockProcess: Partial<ChildProcess> = {
          on: vi.fn((event: string, handler: Function) => {
            if (event === "exit") {
              // Simulate process exit after handler is registered
              setTimeout(() => handler(0), 10);
            }
            if (event === "error") {
              // No error for this test
            }
            return mockProcess;
          }),
          stdout: {
            on: vi.fn((event: string, handler: Function) => {
              if (event === "data") {
                handler(Buffer.from("success output"));
              }
            }),
          } as any,
          stderr: {
            on: vi.fn((event: string, handler: Function) => {
              if (event === "data") {
                // No stderr for this test
              }
            }),
          } as any,
          kill: vi.fn(),
        };

        mockSpawn.mockReturnValue(mockProcess);

        // When: sequant_run tool handler is called
        const result = await client.callTool({
          name: "sequant_run",
          arguments: { issues },
        });

        // Then: It uses child_process.spawn (not spawnSync), returns a Promise
        expect(mockSpawn).toHaveBeenCalled();
        expect(result).toBeDefined();
        expect(result.content).toHaveLength(1);
      });
    });

    describe("negative path: spawn called with correct arguments", () => {
      it("should call spawn with npx and correct command arguments", async () => {
        throw new Error(
          "Test stub - implement this test: verify spawn() is called with 'npx' and correct args array",
        );
      });
    });
  });

  describe("AC-4: Output buffered, truncated to 2000 chars", () => {
    describe("positive path", () => {
      it("should truncate stdout to last 2000 chars when output exceeds limit", async () => {
        // Given: subprocess emits 5000 chars of stdout
        const largeOutput = "x".repeat(5000);
        const issues = [456];

        const mockProcess: Partial<ChildProcess> = {
          on: vi.fn((event: string, handler: Function) => {
            if (event === "exit") {
              setTimeout(() => handler(0), 10);
            }
            return mockProcess;
          }),
          stdout: {
            on: vi.fn((event: string, handler: Function) => {
              if (event === "data") {
                handler(Buffer.from(largeOutput));
              }
            }),
          } as any,
          stderr: {
            on: vi.fn(),
          } as any,
          kill: vi.fn(),
        };

        mockSpawn.mockReturnValue(mockProcess);

        // When: process exits successfully
