          stderr: "error output",
        }),
      );

      const result = await client.callTool({
        name: "sequant_run",
        arguments: { issues: [50] },
      });

      const data = JSON.parse(
        (result.content as Array<{ type: string; text: string }>)[0].text,
      );
      expect(data.output).toBe("standard output");
      expect(data.error).toBe("error output");
    });

    it("should handle mixed stdout and stderr interleaving", async () => {
      // Both stdout and stderr should be captured independently
      mockedSpawn.mockReturnValue(
        createMockProcess({
          exitCode: 0,
          stdout: "out1out2",
          stderr: "err1err2",
        }),
      );

      const result = await client.callTool({
        name: "sequant_run",
        arguments: { issues: [51] },
      });

      const data = JSON.parse(
        (result.content as Array<{ type: string; text: string }>)[0].text,
      );
      expect(data.output).toContain("out1out2");
    });
  });
});

